<template>
  <div>
    <div class="page-head"><div><h2 class="page-title">图片识别</h2><p class="page-subtitle">支持 JPG、PNG、WEBP、BMP 格式</p></div></div>
    <div class="grid-two"><section class="panel form-panel"><file-drop accept=".jpg,.jpeg,.png,.bmp,.webp" label="选择图片文件" @change="handleFile"/><div class="field"><label>置信度 {{ conf }}</label><input v-model.number="conf" type="range" min="0.1" max="0.8" step="0.05"></div><div class="actions"><button class="button" :disabled="!file||loading" @click="submit">{{ loading?'识别中...':'开始识别' }}</button><button class="button secondary" :disabled="!canCapture" @click="openWarning">发布预警</button></div><p v-if="message" class="success-text">{{ message }}</p><p class="error-text">{{ error }}</p></section><result-panel :result="result" media-type="image"/></div>
    <warning-capture-modal :visible="warningVisible" source-type="image" :result="result" @saved="onWarningSaved" @close="warningVisible=false"/>
  </div>
</template>
<script>import FileDrop from "../components/FileDrop.vue";import ResultPanel from "../components/ResultPanel.vue";import WarningCaptureModal from "../components/WarningCaptureModal.vue";export default {name:"ImageDetect",components:{FileDrop,ResultPanel,WarningCaptureModal},data(){return{file:null,conf:0.25,loading:false,error:"",message:"",warningVisible:false,result:null}},computed:{canCapture(){return !this.loading&&!!(this.result&&this.result.id)}},methods:{handleFile(file){this.error="";this.message="";if(!file){this.file=null;this.result=null;return}if(!/\.(jpg|jpeg|png|bmp|webp)$/i.test(file.name)){this.file=null;this.result=null;this.error="请选择图片文件（JPG/PNG/BMP/WEBP）";return}this.file=file;this.result=null},async submit(){if(!this.file){this.error="请选择图片文件";return}this.loading=true;this.error="";this.message="";this.result=null;const f=new FormData();f.append("file",this.file);f.append("conf",this.conf);f.append("source_type","image");try{this.result=await this.$api.upload("/api/detect/image",f)}catch(e){this.error=e.message}finally{this.loading=false}},openWarning(){if(!this.canCapture)return;this.warningVisible=true},onWarningSaved(){this.message="已加入预警提示列表"}}};</script>
<style scoped>.form-panel{padding:20px}input[type="range"]{width:100%;accent-color:#0f766e}.actions{display:flex;flex-wrap:wrap;gap:10px}.success-text{color:#16a34a;min-height:20px;margin-top:10px;font-weight:600}</style>